"""Main application module"""
from typing import List, Dict, Any, Union

class InvalidItemError(Exception):
    """Custom exception for invalid items."""
    pass

def calculate_total(items: List[Dict[str, Union[str, float]]]) -> float:
    """
    Calculate the total price of a list of items.
    """
    total = 0.0
    for item in items:
        validate_item(item)
        total += item.get('price', 0.0)
    return total

def process_order(order_id: str, items: List[Dict[str, Union[str, float]]]) -> Dict[str, Union[str, float]]:
    """
    Processes an order by calculating the total price of the items.
    """
    try:
        total = calculate_total(items)
        return {
            'order_id': order_id,
            'total': total,
            'status': 'processed'
        }
    except InvalidItemError as e:
        return {
            'order_id': order_id,
            'error': str(e),
            'status': 'failed'
        }

def validate_item(item: Dict[str, Union[str, float]]) -> bool:
    """
    Validates an item to ensure it has the required keys ('name' and 'price').
    """
    if 'name' not in item or 'price' not in item:
        raise InvalidItemError(f"Invalid item: {item}. Must contain 'name' and 'price'.")
    return True

if __name__ == '__main__':
    # Valid order
    test_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0}
    ]
    result = process_order('ORD-001', test_items)
    print(f"Order result: {result}")

    # Invalid order
    invalid_items = [
        {'name': 'Item 3'},
        {'price': 30.0}
    ]
    result = process_order('ORD-002', invalid_items)
    print(f"Order result: {result}")

